#include <stdio.h>
#include <string.h>
#include <time.h>
#include <openssl/sha.h>

// 将 SHA256 结果转换为 16 进制字符串
void sha256_to_hex(unsigned char *hash, char *output) {
    for (int i = 0; i < SHA256_DIGEST_LENGTH; i++) {
        sprintf(output + (i * 2), "%02x", hash[i]);
    }
}

/**
 * PoW 核心函数
 * @param block_data 块的数据内容
 * @param difficulty 难度系数（前导零的个数）
 * @param nonce 输出的随机数
 * @param hash_result 输出的哈希字符串
 */
void solve_pow(const char *block_data, int difficulty, unsigned long long *nonce, char *hash_result) {
    unsigned char hash[SHA256_DIGEST_LENGTH];
    char input[512];
    char hex_hash[65];

    // 构造难度目标：例如 difficulty 为 4，则目标是 "0000"
    // 在实际应用中，通常是比较数值大小，这里为了演示直观，使用字符串前缀匹配

    printf("开始挖掘... 目标难度: 前 %d 位为 0\n", difficulty);

    *nonce = 0;
    while (1) {
        // 1. 将数据和当前的 nonce 拼接
        snprintf(input, sizeof(input), "%s%llu", block_data, *nonce);

        // 2. 计算 SHA256
        SHA256((unsigned char *)input, strlen(input), hash);

        // 3. 转为 16 进制字符串
        sha256_to_hex(hash, hex_hash);

        // 4. 检查是否满足难度条件 (检查前导零)
        int match = 1;
        for (int i = 0; i < difficulty; i++) {
            if (hex_hash[i] != '0') {
                match = 0;
                break;
            }
        }

        if (match) {
            strcpy(hash_result, hex_hash);
            return;
        }

        // 5. 否则，增加 nonce 继续尝试
        (*nonce)++;

        // 每 100000 次尝试打印一次进度
        if (*nonce % 100000 == 0) {
            printf("当前尝试次数: %llu...\n", *nonce);
        }
    }
}

int main() {
    const char *data = "Hello, Blockchain!";
    int difficulty = 5; // 难度：前 5 位必须为 0
    unsigned long long nonce = 0;
    char result_hash[65];

    clock_t start = clock();

    solve_pow(data, difficulty, &nonce, result_hash);

    clock_t end = clock();
    double time_spent = (double)(end - start) / CLOCKS_PER_SEC;

    printf("\n--- 挖掘成功! ---\n");
    printf("数据: %s\n", data);
    printf("Nonce: %llu\n", nonce);
    printf("哈希值: %s\n", result_hash);
    printf("耗时: %.4f 秒\n", time_spent);

    return 0;
}
